USE db_atenea;
CREATE TABLE IF NOT EXISTS configuracion_portal_estudiante(id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,clave VARCHAR(100) NOT NULL UNIQUE,valor TEXT NULL,tipo ENUM('texto','imagen') NOT NULL DEFAULT 'texto',grupo ENUM('login','registro','panel','general') NOT NULL,updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP)ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
INSERT INTO configuracion_portal_estudiante(clave,valor,tipo,grupo) VALUES
('login_titulo','Iniciar sesión','texto','login'),('login_subtitulo','Accede a tu cuenta de estudiante de Atenea','texto','login'),('login_texto_boton','Iniciar sesión','texto','login'),('login_imagen_fondo','','imagen','login'),('login_imagen_lateral','src/estudiantes/assets/images/auth/01.png','imagen','login'),('registro_titulo','Crear una cuenta','texto','registro'),('registro_subtitulo','Regístrate como estudiante de Atenea','texto','registro'),('registro_texto_boton','Crear cuenta','texto','registro'),('registro_imagen_fondo','','imagen','registro'),('registro_imagen_lateral','src/estudiantes/assets/images/auth/02.png','imagen','registro'),('panel_titulo','Portal del estudiante','texto','panel'),('panel_subtitulo','Tu espacio de aprendizaje en Atenea','texto','panel'),('panel_texto_bienvenida','Bienvenido a tu portal','texto','panel'),('panel_imagen_banner','','imagen','panel'),('panel_imagen_fondo','','imagen','panel'),('portal_logo','img/atenea-logo.png','imagen','general'),('avatar_predeterminado','src/estudiantes/assets/images/avatars/01.png','imagen','general'),('texto_pie_pagina','Atenea Escuela de Naturopatía Holística','texto','general') ON DUPLICATE KEY UPDATE clave=VALUES(clave);
